import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { ThemeState, ThemeMode } from '../types';

export const useThemeStore = create<ThemeState>()(
  persist(
    (set) => ({
      mode: 'dark',

      backupPreferences: {
        hasBackupFolder: false,
        backupFolderPath: null,
        autoSaveEnabled: false,
        saveInterval: 30000, // 30 seconds
        versionsToKeep: 7,
        customFileName: 'Neuman.Brain',
        reminderPreference: 'every-session',
        nextReminderDate: null,
      },

      toggleTheme: () =>
        set((state) => {
          const newMode: ThemeMode = state.mode === 'dark' ? 'light' : 'dark';

          // Update document class
          if (newMode === 'dark') {
            document.documentElement.classList.add('dark');
          } else {
            document.documentElement.classList.remove('dark');
          }

          return { mode: newMode };
        }),

      updateBackupPreferences: (preferences) =>
        set((state) => ({
          backupPreferences: {
            ...state.backupPreferences,
            ...preferences,
          },
        })),
    }),
    {
      name: 'theme-storage',
      onRehydrateStorage: () => (state) => {
        // Apply theme class on hydration
        if (state?.mode === 'dark') {
          document.documentElement.classList.add('dark');
        } else {
          document.documentElement.classList.remove('dark');
        }
      },
    }
  )
);

import React, { useState, useEffect } from 'react';

export interface BackgroundSettings {
  type: 'none' | 'gradient' | 'image' | 'pattern';
  value: string; // gradient CSS, image URL, or pattern ID
  opacity: number; // 0-100
  blur: number; // 0-20px
}

// Gradient presets
const GRADIENT_PRESETS = [
  {
    name: 'Purple Bliss',
    value: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
  },
  {
    name: 'Sunrise',
    value: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
  },
  {
    name: 'Ocean',
    value: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
  },
  {
    name: 'Sunset',
    value: 'linear-gradient(135deg, #fa709a 0%, #fee140 100%)',
  },
  {
    name: 'Forest',
    value: 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)',
  },
  {
    name: 'Aurora',
    value: 'linear-gradient(135deg, #a8edea 0%, #fed6e3 100%)',
  },
];

interface BackgroundCustomizerProps {
  isOpen: boolean;
  onClose: () => void;
  settings: BackgroundSettings;
  onSettingsChange: (settings: BackgroundSettings) => void;
}

/**
 * Background Customizer Component
 *
 * Allows users to:
 * - Choose background type (none, gradient, image, pattern)
 * - Select from gradient presets or enter custom CSS
 * - Upload custom background images
 * - Adjust opacity (0-100%)
 * - Adjust blur (0-20px)
 * - Preview changes in real-time
 */
export const BackgroundCustomizer: React.FC<BackgroundCustomizerProps> = ({
  isOpen,
  onClose,
  settings,
  onSettingsChange,
}) => {
  const [localSettings, setLocalSettings] = useState<BackgroundSettings>(settings);
  const [imageFile, setImageFile] = useState<string | null>(null);

  useEffect(() => {
    setLocalSettings(settings);
  }, [settings]);

  const handleTypeChange = (type: BackgroundSettings['type']) => {
    setLocalSettings((prev) => ({
      ...prev,
      type,
      value: type === 'gradient' ? GRADIENT_PRESETS[0].value : type === 'none' ? '' : prev.value,
    }));
  };

  const handleGradientSelect = (gradient: string) => {
    setLocalSettings((prev) => ({
      ...prev,
      type: 'gradient',
      value: gradient,
    }));
  };

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const imageUrl = e.target?.result as string;
        setImageFile(imageUrl);
        setLocalSettings((prev) => ({
          ...prev,
          type: 'image',
          value: imageUrl,
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    onSettingsChange(localSettings);
    onClose();
  };

  const handleReset = () => {
    const resetSettings: BackgroundSettings = {
      type: 'none',
      value: '',
      opacity: 100,
      blur: 0,
    };
    setLocalSettings(resetSettings);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="bg-surface-light dark:bg-surface-dark rounded-button shadow-2xl w-full max-w-2xl max-h-[80vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-border-light dark:border-border-dark">
          <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary">
            Customize Background
          </h2>
          <button
            onClick={onClose}
            className="text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary"
            aria-label="Close background customizer"
          >
            ✕
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {/* Background Type Selector */}
          <div className="mb-6">
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
              Background Type
            </label>
            <div className="grid grid-cols-2 gap-2">
              <button
                onClick={() => handleTypeChange('none')}
                className={`px-4 py-2 rounded-button font-medium transition-all duration-standard ease-smooth ${
                  localSettings.type === 'none'
                    ? 'bg-accent-blue dark:bg-accent-cyan text-white'
                    : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary hover:bg-neutral-300 dark:hover:bg-neutral-600'
                }`}
              >
                None
              </button>
              <button
                onClick={() => handleTypeChange('gradient')}
                className={`px-4 py-2 rounded-button font-medium transition-all duration-standard ease-smooth ${
                  localSettings.type === 'gradient'
                    ? 'bg-accent-blue dark:bg-accent-cyan text-white'
                    : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary hover:bg-neutral-300 dark:hover:bg-neutral-600'
                }`}
              >
                Gradient
              </button>
              <button
                onClick={() => handleTypeChange('image')}
                className={`px-4 py-2 rounded-button font-medium transition-all duration-standard ease-smooth ${
                  localSettings.type === 'image'
                    ? 'bg-accent-blue dark:bg-accent-cyan text-white'
                    : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary hover:bg-neutral-300 dark:hover:bg-neutral-600'
                }`}
              >
                Image
              </button>
              <button
                onClick={() => handleTypeChange('pattern')}
                className={`px-4 py-2 rounded-button font-medium transition-all duration-standard ease-smooth ${
                  localSettings.type === 'pattern'
                    ? 'bg-accent-blue dark:bg-accent-cyan text-white'
                    : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary hover:bg-neutral-300 dark:hover:bg-neutral-600'
                }`}
                disabled
                title="Pattern backgrounds coming soon"
              >
                Pattern (Soon)
              </button>
            </div>
          </div>

          {/* Gradient Selector */}
          {localSettings.type === 'gradient' && (
            <div className="mb-6">
              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
                Select Gradient
              </label>
              <div className="grid grid-cols-3 gap-3">
                {GRADIENT_PRESETS.map((preset) => (
                  <button
                    key={preset.name}
                    onClick={() => handleGradientSelect(preset.value)}
                    className={`h-16 rounded-button border-2 transition-all duration-standard ease-smooth ${
                      localSettings.value === preset.value
                        ? 'border-accent-blue dark:border-accent-cyan scale-105'
                        : 'border-border-light dark:border-border-dark hover:scale-105'
                    }`}
                    style={{ background: preset.value }}
                    title={preset.name}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Image Upload */}
          {localSettings.type === 'image' && (
            <div className="mb-6">
              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
                Upload Image
              </label>
              <label className="block w-full px-4 py-8 border-2 border-dashed border-border-light dark:border-border-dark rounded-button cursor-pointer hover:border-accent-blue dark:hover:border-accent-cyan transition-all duration-standard ease-smooth text-center">
                {imageFile ? (
                  <div className="flex flex-col items-center gap-2">
                    <div
                      className="w-full h-32 bg-cover bg-center rounded-button"
                      style={{ backgroundImage: `url(${imageFile})` }}
                    />
                    <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                      Click to change image
                    </span>
                  </div>
                ) : (
                  <div className="flex flex-col items-center gap-2">
                    <svg
                      className="w-12 h-12 text-text-light-secondary dark:text-text-dark-secondary"
                      fill="none"
                      stroke="currentColor"
                      viewBox="0 0 24 24"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        strokeWidth={2}
                        d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                      />
                    </svg>
                    <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                      Click to upload image
                    </span>
                  </div>
                )}
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleImageUpload}
                  className="hidden"
                />
              </label>
            </div>
          )}

          {/* Opacity Slider */}
          {localSettings.type !== 'none' && (
            <div className="mb-6">
              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
                Opacity: {localSettings.opacity}%
              </label>
              <input
                type="range"
                min="0"
                max="100"
                value={localSettings.opacity}
                onChange={(e) =>
                  setLocalSettings((prev) => ({
                    ...prev,
                    opacity: Number(e.target.value),
                  }))
                }
                className="w-full"
              />
            </div>
          )}

          {/* Blur Slider */}
          {localSettings.type !== 'none' && (
            <div className="mb-6">
              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
                Blur: {localSettings.blur}px
              </label>
              <input
                type="range"
                min="0"
                max="20"
                value={localSettings.blur}
                onChange={(e) =>
                  setLocalSettings((prev) => ({
                    ...prev,
                    blur: Number(e.target.value),
                  }))
                }
                className="w-full"
              />
            </div>
          )}

          {/* Preview */}
          {localSettings.type !== 'none' && (
            <div className="mb-6">
              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
                Preview
              </label>
              <div className="relative h-32 rounded-button overflow-hidden border border-border-light dark:border-border-dark">
                <div
                  className="absolute inset-0"
                  style={{
                    backgroundImage: localSettings.value,
                    backgroundSize: localSettings.type === 'image' ? 'cover' : undefined,
                    backgroundPosition: localSettings.type === 'image' ? 'center' : undefined,
                    opacity: localSettings.opacity / 100,
                    filter: `blur(${localSettings.blur}px)`,
                  }}
                />
                <div className="relative z-10 flex items-center justify-center h-full">
                  <div className="bg-white/80 dark:bg-black/80 px-4 py-2 rounded">
                    <p className="text-sm font-medium">Sample Content</p>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between p-6 border-t border-border-light dark:border-border-dark">
          <button
            onClick={handleReset}
            className="px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-button font-medium"
          >
            Reset
          </button>
          <div className="flex gap-2">
            <button
              onClick={onClose}
              className="px-4 py-2 bg-neutral-200 dark:bg-neutral-700 hover:bg-neutral-300 dark:hover:bg-neutral-600 text-text-light-primary dark:text-text-dark-primary rounded-button font-medium"
            >
              Cancel
            </button>
            <button
              onClick={handleSave}
              className="px-4 py-2 bg-accent-blue dark:bg-accent-cyan hover:bg-accent-blue-hover dark:hover:bg-accent-cyan-hover text-white rounded-button font-medium"
            >
              Apply
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

