import React from 'react';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { WidgetResizeHandle } from './WidgetResizeHandle';
import { useWidgetStore } from '../stores/useWidgetStore';

interface SortableWidgetProps {
  id: string;
  children: React.ReactNode;
  className?: string;
}

/**
 * Wrapper component to make dashboard widgets sortable via drag-drop
 * Uses @dnd-kit for drag-drop functionality
 *
 * Phase 5 Enhancements:
 * - Drag handle (prevents accidental drags)
 * - Resize handle (change column spans)
 * - Visual feedback during drag
 * - Accessible keyboard support
 */
export const SortableWidget: React.FC<SortableWidgetProps> = ({ id, children, className = '' }) => {
  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
  const currentSize = widgetSizes[id] || 1;

  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`sortable-widget relative group ${className}`}
    >
      {/* Drag Handle - Only this area is draggable */}
      <button
        {...attributes}
        {...listeners}
        className="drag-handle absolute top-2 right-2 z-10 p-1.5 rounded-buttonhover:bg-neutral-200 dark:hover:bg-neutral-700 cursor-grab active:cursor-grabbing opacity-0 group-hover:opacity-100 transition-opacity"
        aria-label="Drag to reorder widget"
        title="Drag to reorder"
      >
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          className="text-text-light-secondary dark:text-text-dark-secondary"
        >
          <circle cx="6" cy="4" r="1.5" fill="currentColor" />
          <circle cx="10" cy="4" r="1.5" fill="currentColor" />
          <circle cx="6" cy="8" r="1.5" fill="currentColor" />
          <circle cx="10" cy="8" r="1.5" fill="currentColor" />
          <circle cx="6" cy="12" r="1.5" fill="currentColor" />
          <circle cx="10" cy="12" r="1.5" fill="currentColor" />
        </svg>
      </button>

      {/* Resize Handle - Shows on hover */}
      <WidgetResizeHandle widgetId={id} currentSize={currentSize} />

      {/* Widget Content */}
      {children}
    </div>
  );
};

import React from 'react';
import { useWidgetStore } from '../stores/useWidgetStore';

interface WidgetResizeHandleProps {
  widgetId: string;
  currentSize: 1 | 2 | 3;
}

/**
 * Widget Resize Handle Component
 *
 * Provides UI controls to resize widgets between 1x, 2x, and 3x column spans.
 * - Mobile (< 768px): All widgets display as 1 column (sizes ignored)
 * - Tablet/Desktop (≥ 768px): 2-column grid
 *   - 1x = 1 column (50% width)
 *   - 2x = 2 columns (100% width)
 *   - 3x = 2 columns (100% width, treated same as 2x in 2-col grid)
 *
 * Shows on hover with opacity-0 → group-hover:opacity-100
 */
export const WidgetResizeHandle: React.FC<WidgetResizeHandleProps> = ({ widgetId, currentSize }) => {
  const setWidgetSize = useWidgetStore((state) => state.setWidgetSize);

  return (
    <div className="resize-handle-group absolute bottom-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity z-10">
      <button
        onClick={() => setWidgetSize(widgetId, 1)}
        className={`px-2 py-1 text-xs rounded-button font-medium transition-all duration-standard ease-smooth ${
          currentSize === 1
            ? 'bg-accent-blue dark:bg-accent-cyan text-white'
            : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
        }`}
        aria-label="Resize to 1 column width"
        title="Small (1x)"
      >
        1x
      </button>
      <button
        onClick={() => setWidgetSize(widgetId, 2)}
        className={`px-2 py-1 text-xs rounded-button font-medium transition-all duration-standard ease-smooth ${
          currentSize === 2
            ? 'bg-accent-blue dark:bg-accent-cyan text-white'
            : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
        }`}
        aria-label="Resize to 2 columns width"
        title="Medium (2x)"
      >
        2x
      </button>
      <button
        onClick={() => setWidgetSize(widgetId, 3)}
        className={`px-2 py-1 text-xs rounded-button font-medium transition-all duration-standard ease-smooth ${
          currentSize === 3
            ? 'bg-accent-blue dark:bg-accent-cyan text-white'
            : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
        }`}
        aria-label="Resize to 3 columns width (full row)"
        title="Large (3x)"
      >
        3x
      </button>
    </div>
  );
};

