     1→/**
     2→ * Dashboard Widget Store
     3→ *
     4→ * Manages widget state: enabled widgets, order, and settings
     5→ * Persists to localStorage for user preferences
     6→ */
     7→
     8→import { create } from 'zustand';
     9→import { persist } from 'zustand/middleware';
    10→
    11→export interface WidgetSettings {
    12→  refreshRate?: number; // Minutes between auto-refresh
    13→  [key: string]: any; // Widget-specific settings
    14→}
    15→
    16→export interface WidgetState {
    17→  // Enabled widget IDs in display order
    18→  enabledWidgets: string[];
    19→
    20→  // Widget-specific settings
    21→  widgetSettings: Record<string, WidgetSettings>;
    22→
    23→  // Widget sizes (1x, 2x, or 3x width)
    24→  widgetSizes: Record<string, 1 | 2 | 3>;
    25→
    26→  // Actions
    27→  enableWidget: (widgetId: string) => void;
    28→  disableWidget: (widgetId: string) => void;
    29→  reorderWidgets: (newOrder: string[]) => void;
    30→  updateWidgetSettings: (widgetId: string, settings: Partial<WidgetSettings>) => void;
    31→  setWidgetSize: (widgetId: string, size: 1 | 2 | 3) => void;
    32→  isWidgetEnabled: (widgetId: string) => boolean;
    33→  getWidgetSettings: (widgetId: string) => WidgetSettings;
    34→}
    35→
    36→export const useWidgetStore = create<WidgetState>()(
    37→  persist(
    38→    (set, get) => ({
    39→      // Default enabled widgets (core widgets + weathermap only)
    40→      // API widgets (quote, crypto, hackernews, etc.) available in Widget Manager but disabled by default
    41→      enabledWidgets: ['weathermap', 'taskssummary', 'tasksquickadd', 'upcomingevents', 'recentnotes'],
    42→
    43→      // Default widget sizes (2-column grid)
    44→      // WeatherMap: 3x (renders as 2 columns = full row width, locked)
    45→      // Tasks widgets: 1x each (side-by-side in 2 columns)
    46→      // Other core widgets: 1x (1 column = 50% = 2 widgets per row side-by-side)
    47→      widgetSizes: {
    48→        weathermap: 3,
    49→        taskssummary: 1,
    50→        tasksquickadd: 1,
    51→        upcomingevents: 1,
    52→        recentnotes: 1,
    53→      },
    54→
    55→      // Default settings
    56→      widgetSettings: {
    57→        quote: { refreshRate: 60 }, // 1 hour
    58→        crypto: { refreshRate: 1 }, // 1 minute
    59→        hackernews: { refreshRate: 15 }, // 15 minutes
    60→        facts: { refreshRate: 60 },
    61→        github: { refreshRate: 60, username: '' },
    62→        weather: { refreshRate: 60 },
    63→        joke: { refreshRate: 30 },
    64→        unsplash: { refreshRate: 60, category: 'nature' },
    65→        pomodoro: { duration: 25 }, // 25 minutes
    66→        reddit: { refreshRate: 15, subreddit: 'programming' },
    67→        devto: { refreshRate: 30 },
    68→        wordofday: { refreshRate: 1440 }, // Once per day
    69→        currency: { refreshRate: 60 },
    70→        worldclock: {},
    71→        ipinfo: { refreshRate: 60 },
    72→        qrcode: {},
    73→        colorpalette: {},
    74→        weathermap: { refreshRate: 60 },
    75→      },
    76→
    77→      enableWidget: (widgetId) => {
    78→        set((state) => {
    79→          if (!state.enabledWidgets.includes(widgetId)) {
    80→            return {
    81→              enabledWidgets: [...state.enabledWidgets, widgetId],
    82→              widgetSizes: { ...state.widgetSizes, [widgetId]: state.widgetSizes[widgetId] || 1 },
    83→            };
    84→          }
    85→          return state;
    86→        });
    87→      },
    88→
    89→      disableWidget: (widgetId) => {
    90→        set((state) => {
    91→          const { [widgetId]: _, ...remainingSizes } = state.widgetSizes;
    92→          return {
    93→            enabledWidgets: state.enabledWidgets.filter((id) => id !== widgetId),
    94→            widgetSizes: remainingSizes,
    95→          };
    96→        });
    97→      },
    98→
    99→      reorderWidgets: (newOrder) => {
   100→        set({ enabledWidgets: newOrder });
   101→      },
   102→
   103→      updateWidgetSettings: (widgetId, settings) => {
   104→        set((state) => ({
   105→          widgetSettings: {
   106→            ...state.widgetSettings,
   107→            [widgetId]: {
   108→              ...state.widgetSettings[widgetId],
   109→              ...settings,
   110→            },
   111→          },
   112→        }));
   113→      },
   114→
   115→      setWidgetSize: (widgetId, size) => {
   116→        set((state) => ({
   117→          widgetSizes: {
   118→            ...state.widgetSizes,
   119→            [widgetId]: size,
   120→          },
   121→        }));
   122→      },
   123→
   124→      isWidgetEnabled: (widgetId) => {
   125→        return get().enabledWidgets.includes(widgetId);
   126→      },
   127→
   128→      getWidgetSettings: (widgetId) => {
   129→        return get().widgetSettings[widgetId] || {};
   130→      },
   131→    }),
   132→    {
   133→      name: 'dashboard-widgets',
   134→      version: 4, // Increment this when you need to trigger migrations
   135→      migrate: (persistedState: any, version: number) => {
   136→        const state = persistedState as WidgetState;
   137→
   138→        // Migration for version 0 -> 1: Add weathermap to enabled widgets if missing
   139→        if (version === 0) {
   140→          if (!state.enabledWidgets.includes('weathermap')) {
   141→            state.enabledWidgets.push('weathermap');
   142→          }
   143→          if (!state.widgetSettings.weathermap) {
   144→            state.widgetSettings.weathermap = { refreshRate: 60 };
   145→          }
   146→        }
   147→
   148→        // Migration for version 1 -> 2: Add widgetSizes if missing, set weathermap to 2x
   149→        if (version < 2) {
   150→          if (!state.widgetSizes) {
   151→            state.widgetSizes = {};
   152→          }
   153→          // Set weathermap to 2x width by default
   154→          if (!state.widgetSizes.weathermap) {
   155→            state.widgetSizes.weathermap = 2;
   156→          }
   157→        }
   158→
   159→        // Migration for version 2 -> 3: Update widget defaults (2-column grid)
   160→        if (version < 3) {
   161→          // Update weathermap to 3x (full row in 2-column grid)
   162→          state.widgetSizes.weathermap = 3;
   163→
   164→          // Set core widgets to 1x width (50% = half row in 2-column grid)
   165→          const coreWidgets = ['tasksummary', 'upcomingevents', 'recentnotes', 'quickadd'];
   166→          coreWidgets.forEach((widgetId) => {
   167→            if (!state.widgetSizes[widgetId]) {
   168→              state.widgetSizes[widgetId] = 1;
   169→            }
   170→          });
   171→
   172→          // Note: API widgets (quote, crypto, hackernews) are now disabled by default
   173→          // but remain available in Widget Manager. This migration doesn't force-remove
   174→          // them if user already has them enabled - existing preferences are preserved.
   175→        }
   176→
   177→        // Migration for version 3 -> 4: Merge tasksummary + quickadd into tasksquickadd
   178→        if (version < 4) {
   179→          // Replace tasksummary and quickadd with tasksquickadd
   180→          const hasTaskSummary = state.enabledWidgets.includes('tasksummary');
   181→          const hasQuickAdd = state.enabledWidgets.includes('quickadd');
   182→
   183→          if (hasTaskSummary || hasQuickAdd) {
   184→            // Remove old widgets
   185→            state.enabledWidgets = state.enabledWidgets.filter(
   186→              (id) => id !== 'tasksummary' && id !== 'quickadd'
   187→            );
   188→
   189→            // Add new combined widget at position 1 (after weathermap at position 0)
   190→            if (!state.enabledWidgets.includes('tasksquickadd')) {
   191→              state.enabledWidgets.splice(1, 0, 'tasksquickadd');
   192→            }
   193→
   194→            // Set size to 3x (full row)
   195→            state.widgetSizes.tasksquickadd = 3;
   196→
   197→            // Clean up old widget sizes
   198→            delete state.widgetSizes.tasksummary;
   199→            delete state.widgetSizes.quickadd;
   200→          }
   201→        }
   202→
   203→        return persistedState;
   204→      },
   205→    }
   206→  )
   207→);
